[DataContractAttribute]
 class ETGSalesagreementLineAPIContract
{

        private ItemId itemId;
        private AgreementCommitedQuantity quantity;
        private UnitOfMeasureSymbol unit;
        private AgreementPricePerUnit unitPrice;
        private InventSiteId site;
        private InventLocationId warehouse;
        private WMSLocationId location;
        private EcoResItemConfigurationName configId;
        private EcoResItemSizeName size;
        private EcoResItemColorName color;
        private EcoResItemStyleName style;
        private UnderDeliveryPct underDelivery;
        private OverDeliveryPct overDelivery;
        private str dealNumber;

}

